class Solution:
    def count(self, num1: str, num2: str, min_sum: int, max_sum: int) -> int:
        MOD = 1_000_000_007
        lo, hi = int(num1), int(num2)
        total = 0
        for x in range(lo, hi + 1):
            s = sum(int(ch) for ch in str(x))
            if min_sum <= s <= max_sum:
                total += 1
        return total % MOD

