class Solution:
    def count(self, num1: str, num2: str, min_sum: int, max_sum: int) -> int:
        MOD = 1_000_000_007

        def sub_one(num: str) -> str:
            digits = list(num)
            i = len(digits) - 1
            while i >= 0 and digits[i] == '0':
                digits[i] = '9'
                i -= 1
            if i < 0:
                return '0'
            digits[i] = str(int(digits[i]) - 1)
            result = ''.join(digits).lstrip('0')
            return result if result else '0'

        def count_upto(n: str, cap: int) -> int:
            if cap < 0:
                return 0
            digits = [int(ch) for ch in n]
            L = len(digits)
            from functools import lru_cache

            @lru_cache(maxsize=None)
            def dp(pos: int, remaining: int, tight: bool) -> int:
                if remaining < 0:
                    return 0
                if pos == L:
                    return 1
                limit = digits[pos] if tight else 9
                total = 0
                for d in range(0, limit + 1):
                    total += dp(pos + 1, remaining - d, tight and d == limit)
                return total

            result = dp(0, cap, True)
            dp.cache_clear()
            return result

        upper = count_upto(num2, max_sum) - count_upto(num2, min_sum - 1)
        num1_minus_1 = sub_one(num1)
        lower = count_upto(num1_minus_1, max_sum) - count_upto(num1_minus_1, min_sum - 1)
        return (upper - lower) % MOD

