var count = function(num1, num2, min_sum, max_sum) {
    const MOD = 1000000007n;

    function subOne(num) {
        const digits = num.split('');
        let i = digits.length - 1;
        while (i >= 0 && digits[i] === '0') {
            digits[i] = '9';
            i -= 1;
        }
        if (i < 0) return '0';
        digits[i] = String(Number(digits[i]) - 1);
        let result = digits.join('').replace(/^0+/, '');
        return result === '' ? '0' : result;
    }

    function countUpto(n, cap) {
        if (cap < 0) return 0n;
        const digits = n.split('').map(Number);
        const L = digits.length;
        const memo = new Map();

        function dp(pos, remaining, tight) {
            if (remaining < 0) return 0n;
            if (pos === L) return 1n;
            const key = pos + ',' + remaining + ',' + (tight ? 1 : 0);
            if (memo.has(key)) return memo.get(key);
            const limit = tight ? digits[pos] : 9;
            let total = 0n;
            for (let d = 0; d <= limit; d++) {
                total += dp(pos + 1, remaining - d, tight && d === limit);
            }
            memo.set(key, total);
            return total;
        }

        return dp(0, cap, true);
    }

    const upper = ((countUpto(num2, max_sum) - countUpto(num2, min_sum - 1)) % MOD + MOD) % MOD;
    const num1Minus1 = subOne(num1);
    const lower = ((countUpto(num1Minus1, max_sum) - countUpto(num1Minus1, min_sum - 1)) % MOD + MOD) % MOD;
    const ans = ((upper - lower) % MOD + MOD) % MOD;
    return Number(ans);
};
